import{_ as d,a as e,b as o,c as a,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as c}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as i,o as l,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"OCR（文字识别）使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/ocr.md","filePath":"cn/Other/ocr.md","lastUpdated":1781962217000}'),h={name:"cn/Other/ocr.md"};function p(b,t,P,u,g,m){return l(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="ocr-文字识别-使用说明" tabindex="-1"><code>OCR</code>（文字识别）使用说明 <a class="header-anchor" href="#ocr-文字识别-使用说明" aria-label="Permalink to &quot;`OCR`（文字识别）使用说明&quot;">​</a></h1><p><code>OCR</code>（文字识别）可以把图片、扫描件、文档截图里的文字识别出来。<br> 识别完成后，可以复制结果，也可以导出成 <code>Markdown</code>（Markdown 文档）、<code>PDF</code>（PDF 文档）、<code>Word</code>（Word 文档），或者把多种格式一起打包下载。</p><h2 id="这个功能能做什么" tabindex="-1">这个功能能做什么 <a class="header-anchor" href="#这个功能能做什么" aria-label="Permalink to &quot;这个功能能做什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>图片文字识别</td><td>识别图片、截图、扫描件里的文字。</td></tr><tr><td>文档版面识别</td><td>对表格、公式、印章、图文混排这类文档更友好。</td></tr><tr><td>多服务选择</td><td>支持百度飞桨 <code>PaddleOCR</code>（飞桨文字识别）、微软 <code>Azure Vision</code>（微软视觉识别）、谷歌 <code>Google Vision</code>（谷歌视觉识别）。</td></tr><tr><td>结果复制</td><td>识别完成后，可以直接复制文字结果。</td></tr><tr><td>导出文件</td><td>支持导出 <code>Markdown</code>（Markdown 文档）、<code>PDF</code>（PDF 文档）、<code>Word</code>（Word 文档）。</td></tr><tr><td>批量打包</td><td>多个文件识别后，可以把结果打包下载。</td></tr></tbody></table><h2 id="先配置识别服务" tabindex="-1">先配置识别服务 <a class="header-anchor" href="#先配置识别服务" aria-label="Permalink to &quot;先配置识别服务&quot;">​</a></h2><p>入口在：</p><p>系统配置 -&gt; 其他设置 -&gt; <code>OCR</code>（文字识别）</p><p><img src="'+d+'" alt="IP定位和OCR文字识别" loading="lazy"></p><p>这里可以填写不同识别服务的凭据：</p><table tabindex="0"><thead><tr><th>服务</th><th>后台要填什么</th><th>适合场景</th></tr></thead><tbody><tr><td>百度飞桨 <code>PaddleOCR</code>（飞桨文字识别）</td><td><code>PaddleOCR Token</code>（飞桨访问令牌）</td><td>推荐优先使用，适合文档、图片、表格、图文混排。</td></tr><tr><td>微软 <code>Azure Vision</code>（微软视觉识别）</td><td><code>Azure Vision Endpoint</code>（微软接口地址）和 <code>Azure Vision API Key</code>（微软密钥）</td><td>适合使用微软云服务的用户。</td></tr><tr><td>谷歌 <code>Google Vision</code>（谷歌视觉识别）</td><td><code>Google Vision API Key</code>（谷歌密钥）。服务账号 <code>JSON</code>（账号配置文件）只用于查询额度。</td><td>适合使用谷歌云服务的用户。</td></tr></tbody></table><p>填好后点击保存。<br> 只想先试用的话，可以先配置一个服务，不需要三个都填。</p><h2 id="谷歌-google-vision-谷歌视觉识别-怎么配置" tabindex="-1">谷歌 <code>Google Vision</code>（谷歌视觉识别）怎么配置 <a class="header-anchor" href="#谷歌-google-vision-谷歌视觉识别-怎么配置" aria-label="Permalink to &quot;谷歌 `Google Vision`（谷歌视觉识别）怎么配置&quot;">​</a></h2><p>谷歌这里分两件事：</p><table tabindex="0"><thead><tr><th>要做什么</th><th>需要准备什么</th></tr></thead><tbody><tr><td>使用 <code>OCR</code>（文字识别）</td><td>启用 <code>Cloud Vision API</code>（云视觉接口），然后创建 <code>API Key</code>（接口密钥）。</td></tr><tr><td>查询使用次数</td><td>创建服务账号，给 <code>Monitoring Viewer</code>（监控查看者）角色，再下载服务账号 <code>JSON</code>（账号配置文件）。</td></tr></tbody></table><p><img src="'+c+'" alt="谷歌API密钥和服务账号截图" loading="lazy"></p><h3 id="用谷歌做-ocr-文字识别" tabindex="-1">用谷歌做 <code>OCR</code>（文字识别） <a class="header-anchor" href="#用谷歌做-ocr-文字识别" aria-label="Permalink to &quot;用谷歌做 `OCR`（文字识别）&quot;">​</a></h3><p>操作顺序如下：</p><ol><li>打开 <code>Google Cloud Console</code>（谷歌云控制台）。</li><li>进入 <code>API 和服务</code>（API 和服务）。</li><li>打开 <code>库</code>（库），搜索并启用 <code>Cloud Vision API</code>（云视觉接口）。</li><li>回到 <code>凭证</code>（凭证）。</li><li>点击创建凭证，创建 <code>API Key</code>（接口密钥）。</li><li>点开这个 <code>API Key</code>（接口密钥），复制密钥内容。</li><li>回到图床后台，把密钥粘贴到 <code>Google Vision API Key</code>（谷歌视觉接口密钥）里。</li><li>点击保存。</li></ol><p>这样就可以在 <code>OCR</code>（文字识别）弹窗里选择谷歌 <code>Google Vision</code>（谷歌视觉识别）来识别图片。</p><h3 id="查询谷歌使用次数" tabindex="-1">查询谷歌使用次数 <a class="header-anchor" href="#查询谷歌使用次数" aria-label="Permalink to &quot;查询谷歌使用次数&quot;">​</a></h3><p>查询额度不是识别必需项。<br> 它只是用来查看谷歌 <code>Google Vision</code>（谷歌视觉识别）最近 30 天大概用了多少次。</p><p>操作顺序如下：</p><ol><li>在 <code>Google Cloud Console</code>（谷歌云控制台）进入 <code>IAM 和管理</code>（身份和权限管理）。</li><li>打开 <code>服务账号</code>（服务账号）。</li><li>创建一个服务账号，例如 <code>vision-monitor</code>（视觉用量监控）。</li><li>给这个服务账号添加 <code>Monitoring Viewer</code>（监控查看者）角色。</li><li>进入服务账号详情，创建密钥。</li><li>密钥类型选择 <code>JSON</code>（账号配置文件）。</li><li>下载生成的 <code>JSON</code>（账号配置文件）。</li><li>回到图床后台，在服务账号 <code>JSON</code>（可选）这里点击导入。</li><li>导入成功后，再点击查询额度。</li></ol><p>导入成功后，后台会显示这个服务账号所属的项目名。<br> 点查询额度时，系统会读取谷歌监控数据，然后显示这个月已经调用了多少次。</p><p>简单理解就是：</p><table tabindex="0"><thead><tr><th>内容</th><th>作用</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code>（谷歌视觉接口密钥）</td><td>用来真正识别图片。</td></tr><tr><td>服务账号 <code>JSON</code>（账号配置文件）</td><td>用来查询谷歌接口用了多少次。</td></tr><tr><td><code>Monitoring Viewer</code>（监控查看者）角色</td><td>让服务账号可以读取用量数据。</td></tr></tbody></table><h2 id="获取百度飞桨令牌" tabindex="-1">获取百度飞桨令牌 <a class="header-anchor" href="#获取百度飞桨令牌" aria-label="Permalink to &quot;获取百度飞桨令牌&quot;">​</a></h2><p>百度飞桨 <code>PaddleOCR</code>（飞桨文字识别）需要先拿到访问令牌。</p><p><img src="'+e+'" alt="获取飞浆令牌" loading="lazy"></p><p>在百度飞桨页面里打开 <code>API</code>（接口）调用窗口，点击获取令牌，然后复制令牌内容。<br> 回到图床后台，把令牌粘贴到 <code>PaddleOCR Token</code>（飞桨访问令牌）里保存即可。</p><h2 id="开始识别" tabindex="-1">开始识别 <a class="header-anchor" href="#开始识别" aria-label="Permalink to &quot;开始识别&quot;">​</a></h2><p>在文件管理里选中一个图片或文档截图，点击 <code>OCR</code>（文字识别）按钮。</p><p><img src="'+o+'" alt="OCR识别截图" loading="lazy"></p><p>弹窗里可以选择识别接口和识别模型。</p><p>百度飞桨 <code>PaddleOCR</code>（飞桨文字识别）常用模型可以这样选：</p><table tabindex="0"><thead><tr><th>模型</th><th>适合场景</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code>（结构化文档识别）</td><td>推荐默认使用，适合文档、表格、公式、印章、图文混排。</td></tr><tr><td><code>PP-OCRv5</code>（通用文字识别）</td><td>适合简单图片、普通文字、轻量识别。</td></tr><tr><td><code>PaddleOCR-VL</code>（视觉语言模型）</td><td>适合多语言、复杂图片、图表类内容。</td></tr><tr><td><code>PaddleOCR-VL-1.5</code>（增强视觉语言模型）</td><td>适合更复杂的文档页面和版面恢复。</td></tr></tbody></table><p>不确定选哪个时，先用 <code>PP-StructureV3</code>（结构化文档识别）即可。</p><h2 id="高级选项" tabindex="-1">高级选项 <a class="header-anchor" href="#高级选项" aria-label="Permalink to &quot;高级选项&quot;">​</a></h2><p>识别弹窗里有高级选项，常用理解如下：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td>方向校正</td><td>图片拍歪、旋转时可以打开。</td></tr><tr><td>文档展平</td><td>拍照文档有弯曲、倾斜时可以打开。</td></tr><tr><td>版面检测</td><td>想保留标题、段落、表格、图片结构时建议打开。</td></tr><tr><td>图表识别</td><td>图片里有图表、复杂结构时再打开。</td></tr><tr><td>美化 <code>Markdown</code>（Markdown 文档）</td><td>导出 <code>Markdown</code>（Markdown 文档）时更容易阅读。</td></tr></tbody></table><p>普通截图可以少开选项，文档扫描件可以多开一些。</p><h2 id="查看识别结果" tabindex="-1">查看识别结果 <a class="header-anchor" href="#查看识别结果" aria-label="Permalink to &quot;查看识别结果&quot;">​</a></h2><p>识别完成后，弹窗里会显示识别结果。<br> 可以直接复制，也可以选择导出格式后点击导出。</p><p><img src="'+a+'" alt="PDF识别截图" loading="lazy"></p><p>如果识别的是文档页面，<code>PDF</code>（PDF 文档）导出后可以保留页面效果，并且文字可以搜索。<br> 这类结果适合保存原始版面，后面查找内容也方便。</p><h2 id="导出格式怎么选" tabindex="-1">导出格式怎么选 <a class="header-anchor" href="#导出格式怎么选" aria-label="Permalink to &quot;导出格式怎么选&quot;">​</a></h2><table tabindex="0"><thead><tr><th>导出格式</th><th>适合场景</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code>（Markdown 文档）</td><td>适合整理笔记、复制到文档系统、后续继续编辑。</td></tr><tr><td><code>PDF (.pdf)</code>（PDF 文档）</td><td>适合保留页面效果，保存扫描件识别结果。</td></tr><tr><td><code>Word (.docx)</code>（Word 文档）</td><td>适合继续排版、修改文字、交给别人编辑。</td></tr><tr><td>全部导出</td><td>同时保存多种格式和原图，适合重要文件归档。</td></tr></tbody></table><p>如果只是要文字，导出 <code>Markdown</code>（Markdown 文档）最轻。<br> 如果还要页面效果，导出 <code>PDF</code>（PDF 文档）或 <code>Word</code>（Word 文档）更合适。</p><h2 id="word-word-文档-效果" tabindex="-1"><code>Word</code>（Word 文档）效果 <a class="header-anchor" href="#word-word-文档-效果" aria-label="Permalink to &quot;`Word`（Word 文档）效果&quot;">​</a></h2><p>导出 <code>Word</code>（Word 文档）后，可以用办公软件打开继续编辑。</p><p><img src="'+r+`" alt="Word识别结果" loading="lazy"></p><p>有些文档会把识别到的图片、标题、段落一起放进 <code>Word</code>（Word 文档）里。<br> 识别效果和原图清晰度、模型选择、文档复杂度都有关系。</p><h2 id="哪些文件更适合识别" tabindex="-1">哪些文件更适合识别 <a class="header-anchor" href="#哪些文件更适合识别" aria-label="Permalink to &quot;哪些文件更适合识别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件类型</th><th>建议</th></tr></thead><tbody><tr><td>清晰截图</td><td>直接识别即可。</td></tr><tr><td>扫描件</td><td>优先用 <code>PP-StructureV3</code>（结构化文档识别）。</td></tr><tr><td>拍照文档</td><td>可以打开方向校正、文档展平。</td></tr><tr><td>表格/公式/印章</td><td>优先用结构化模型。</td></tr><tr><td>普通短文字图片</td><td><code>PP-OCRv5</code>（通用文字识别）就够用。</td></tr></tbody></table><p>图片越清晰、文字越端正，识别结果通常越好。</p><h2 id="常见情况" tabindex="-1">常见情况 <a class="header-anchor" href="#常见情况" aria-label="Permalink to &quot;常见情况&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>说明</th></tr></thead><tbody><tr><td>识别失败</td><td>先检查对应服务的令牌或密钥有没有保存。</td></tr><tr><td>识别很慢</td><td>文档越复杂、图片越大，等待时间越长。</td></tr><tr><td>表格不完整</td><td>可以换结构化模型重新识别。</td></tr><tr><td>文字有错字</td><td>原图模糊、反光、倾斜时更容易出错，可以换更清晰的图片。</td></tr><tr><td><code>Word</code>（Word 文档）里图片较多</td><td>结构化模型会保留部分识别图片，这是正常情况。</td></tr></tbody></table><h3 id="谷歌查询额度失败" tabindex="-1">谷歌查询额度失败 <a class="header-anchor" href="#谷歌查询额度失败" aria-label="Permalink to &quot;谷歌查询额度失败&quot;">​</a></h3><p>先检查三件事：</p><ol><li>是否已经导入服务账号 <code>JSON</code>（账号配置文件）。</li><li>服务账号是否有 <code>Monitoring Viewer</code>（监控查看者）角色。</li><li>当前项目是否已经启用 <code>Cloud Vision API</code>（云视觉接口）。</li></ol><p>如果只是识别图片，不查询次数，可以先不管服务账号 <code>JSON</code>（账号配置文件），只填 <code>Google Vision API Key</code>（谷歌视觉接口密钥）就行。</p><h2 id="简单流程" tabindex="-1">简单流程 <a class="header-anchor" href="#简单流程" aria-label="Permalink to &quot;简单流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开系统配置</span></span>
<span class="line"><span>-&gt; 进入其他设置</span></span>
<span class="line"><span>-&gt; 填写 OCR 服务凭据</span></span>
<span class="line"><span>-&gt; 保存</span></span>
<span class="line"><span>-&gt; 回到文件管理</span></span>
<span class="line"><span>-&gt; 选中文件并点击 OCR 识别</span></span>
<span class="line"><span>-&gt; 选择模型</span></span>
<span class="line"><span>-&gt; 等待识别完成</span></span>
<span class="line"><span>-&gt; 复制结果或导出 Markdown / PDF / Word</span></span></code></pre></div>`,63)])])}const y=i(h,[["render",p]]);export{_ as __pageData,y as default};
